        '# LT三層\n'
        'pr["實際LT"]   = (pr["實際到貨"] - pr["下單日"]).dt.days\n'
        'pr["計畫LT"]   = (pr["預計到貨"] - pr["下單日"]).dt.days\n'
        'pr["LT延遲日"] = pr["實際LT"] - pr["計畫LT"]\n'
        'print(pr.head())',
